const input = $input.first().json || {};
const rawResponse = input.response;

const normalizeParsed = (parsed) => {
  if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
    return {
      campo: parsed.campo ?? input.body?.dados?.campo ?? null,
      conteudo: (parsed.conteudo ?? '').toString().trim() || JSON.stringify(parsed),
      erro: parsed.erro ?? null,
      debug: parsed.debug ?? null,
    };
  }

  return {
    campo: input.body?.dados?.campo ?? null,
    conteudo: (parsed ?? '').toString().trim(),
    erro: null,
    debug: null,
  };
};

try {
  if (rawResponse === undefined || rawResponse === null) {
    throw new Error('A resposta da IA veio vazia');
  }

  if (typeof rawResponse === 'object') {
    return normalizeParsed(rawResponse);
  }

  const asString = rawResponse.toString();
  const cleanData = asString.replace(/```json|```/gi, '').replace(/<[^>]*>/g, '').trim();

  if (!cleanData) {
    throw new Error('A resposta da IA veio vazia após limpeza');
  }

  try {
    const parsed = JSON.parse(cleanData);
    return normalizeParsed(parsed);
  } catch {
    return normalizeParsed(cleanData);
  }
} catch (e) {
  return {
    campo: input.body?.dados?.campo ?? null,
    conteudo: 'Falha ao processar resposta da IA.',
    erro: {
      code: 'PARSE_ERROR',
      message: e.message,
    },
    debug: {
      rawType: typeof rawResponse,
    },
  };
}

const input = $input.first().json || {};
const body = input.body ?? {};
const dados = body.dados ?? {};
const conteudo = (dados.conteudo ?? '').toString().trim();
const aba = (body.aba ?? '').toString().trim();
const campo = (dados.campo ?? '').toString().trim();

const errors = [];
if (!aba) errors.push('Campo obrigatório ausente: body.aba');
if (!campo) errors.push('Campo obrigatório ausente: body.dados.campo');
if (!conteudo) errors.push('Campo obrigatório ausente: body.dados.conteudo');

return {
  ...input,
  body: {
    ...body,
    dados: {
      ...dados,
      conteudo,
      campo,
      estado_atual: dados.estado_atual ?? { dados_gerais: {} },
    },
  },
  _validation: {
    isValid: errors.length === 0,
    errors,
  },
};

const input = $input.first().json || {};
const aba = (input.body?.aba ?? '').toString().trim();
const campo = (input.body?.dados?.campo ?? '').toString().trim();
const validationErrors = input._validation?.errors ?? [];

let code = 'ROUTING_ERROR';
let message = 'Não foi possível rotear a requisição no workflow.';

if (validationErrors.length > 0) {
  code = 'VALIDATION_ERROR';
  message = 'Payload inválido. Corrija os campos obrigatórios e tente novamente.';
} else if (aba && aba !== 'dados_gerais') {
  code = 'UNSUPPORTED_ABA';
  message = `Aba não suportada: ${aba}. Valor esperado: dados_gerais.`;
} else if (campo) {
  code = 'UNSUPPORTED_CAMPO';
  message = `Campo não suportado: ${campo}.`;
}

return {
  campo: campo || null,
  conteudo: message,
  erro: { code, message, details: validationErrors },
  debug: { aba: aba || null, campo: campo || null },
};
